     1→import React from 'react';
     2→import { Mock, MockInstance, vi } from 'vitest';
     3→import { act, render, screen } from '@testing-library/react';
     4→import { ResponsiveContainer } from '../../src';
     5→import { mockGetBoundingClientRect } from '../helper/mockGetBoundingClientRect';
     6→
     7→declare global {
     8→  interface Window {
     9→    ResizeObserver: unknown;
    10→  }
    11→}
    12→
    13→describe('<ResponsiveContainer />', () => {
    14→  /**
    15→   * Use this function to simulate a change fired by a window.ResizeObserver
    16→   * You just need to pass a param with ResizeObserverEntry structure like:
    17→   *
    18→   * @see https://developer.mozilla.org/en-US/docs/Web/API/ResizeObserverEntry
    19→   */
    20→  let notifyResizeObserverChange: (arg: unknown) => void,
    21→    consoleWarnSpy: MockInstance<(...args: any[]) => void>,
    22→    resizeObserverMock: Mock<(arg: any) => any>;
    23→
    24→  beforeEach(() => {
    25→    /**
    26→     * ResizeObserver is not available, so we have to create a mock to avoid error coming
    27→     * from `react-resize-detector`.
    28→     * @see https://github.com/maslianok/react-resize-detector/issues/145
    29→     *
    30→     * This mock also allow us to use {@link notifyResizeObserverChange} to fire changes
    31→     * from inside our test.
    32→     */
    33→    resizeObserverMock = vi.fn().mockImplementation(callback => {
    34→      notifyResizeObserverChange = callback;
    35→
    36→      return {
    37→        observe: vi.fn(),
    38→        unobserve: vi.fn(),
    39→        disconnect: vi.fn(),
    40→      };
    41→    });
    42→    consoleWarnSpy = vi.spyOn(console, 'warn').mockImplementation((): void => undefined);
    43→
    44→    delete window.ResizeObserver;
    45→
    46→    window.ResizeObserver = resizeObserverMock;
    47→  });
    48→
    49→  it('Render a wrapper container in ResponsiveContainer', () => {
    50→    const { container } = render(
    51→      <ResponsiveContainer>
    52→        <div data-testid="inside" />
    53→      </ResponsiveContainer>,
    54→    );
    55→
    56→    expect(container.querySelector('.recharts-responsive-container')).toBeTruthy();
    57→
    58→    // should issue a warning since no dimension is set, therefore they are 0
    59→    expect(consoleWarnSpy).toHaveBeenCalled();
    60→    expect(consoleWarnSpy).toHaveBeenCalledWith(expect.any(String));
    61→  });
    62→
    63→  it('Renders with minHeight and minWidth when provided', () => {
    64→    const { container } = render(
    65→      <ResponsiveContainer minWidth={200} minHeight={100}>
    66→        <div data-testid="inside" />
    67→      </ResponsiveContainer>,
    68→    );
    69→
    70→    expect(container.querySelector('.recharts-responsive-container')).toHaveStyle({
    71→      minWidth: '200px',
    72→      minHeight: '100px',
    73→    });
    74→  });
    75→
    76→  it('Renders the component inside', () => {
    77→    render(
    78→      <ResponsiveContainer minWidth={200} minHeight={100}>
    79→        <div data-testid="inside" />
    80→      </ResponsiveContainer>,
    81→    );
    82→
    83→    expect(screen.getByTestId('inside')).toBeTruthy();
    84→  });
    85→
    86→  it('Handles zero height correctly', () => {
    87→    render(
    88→      <ResponsiveContainer height={0} aspect={2} width={300}>
    89→        <div data-testid="inside" />
    90→      </ResponsiveContainer>,
    91→    );
    92→
    93→    expect(screen.getByTestId('inside')).toHaveAttribute('width', '300');
    94→    expect(screen.getByTestId('inside')).toHaveAttribute('height', '150');
    95→  });
    96→
    97→  it('Handles zero width correctly', () => {
    98→    render(
    99→      <ResponsiveContainer height={300} aspect={2} width={0}>
   100→        <div data-testid="inside" />
   101→      </ResponsiveContainer>,
   102→    );
   103→
   104→    expect(screen.getByTestId('inside')).toHaveAttribute('width', '600');
   105→    expect(screen.getByTestId('inside')).toHaveAttribute('height', '300');
   106→  });
   107→
   108→  // Note that we force height and width here which will trigger a warning.
   109→  // Unfortunately ContainerDimensions does not measure with enzyme
   110→  // so we have to force it to test aspect handling behaviors
   111→  it('Preserves aspect ratio when oversized', () => {
   112→    render(
   113→      <ResponsiveContainer aspect={2} height={100} width={300}>
   114→        <div data-testid="inside" />
   115→      </ResponsiveContainer>,
   116→    );
   117→
   118→    expect(screen.getByTestId('inside')).toHaveAttribute('width', '300');
   119→    expect(screen.getByTestId('inside')).toHaveAttribute('height', '150');
   120→  });
   121→
   122→  it('Preserves aspect ratio when undersized', () => {
   123→    render(
   124→      <ResponsiveContainer aspect={2} height={300} width={100}>
   125→        <div data-testid="inside" />
   126→      </ResponsiveContainer>,
   127→    );
   128→
   129→    expect(screen.getByTestId('inside')).toHaveAttribute('width', '100');
   130→    expect(screen.getByTestId('inside')).toHaveAttribute('height', '50');
   131→  });
   132→
   133→  it('Renders without an id attribute when not passed', () => {
   134→    const { container } = render(
   135→      <ResponsiveContainer>
   136→        <div data-testid="inside" />
   137→      </ResponsiveContainer>,
   138→    );
   139→
   140→    expect(container.querySelector('.recharts-responsive-container')).not.toHaveAttribute('id');
   141→  });
   142→
   143→  it('Renders with id attribute when passed', () => {
   144→    const { container } = render(
   145→      <ResponsiveContainer id="testing-id-attr">
   146→        <div data-testid="inside" />
   147→      </ResponsiveContainer>,
   148→    );
   149→
   150→    expect(container.querySelector('.recharts-responsive-container')).toHaveAttribute('id', 'testing-id-attr');
   151→  });
   152→
   153→  it('should resize when ResizeObserver notify a change', () => {
   154→    const { container } = render(
   155→      <ResponsiveContainer id="testing-id-attr" width="100%" height={200}>
   156→        <div data-testid="inside" />
   157→      </ResponsiveContainer>,
   158→    );
   159→
   160→    const element = container.querySelector('.recharts-responsive-container');
   161→    expect(element).not.toHaveAttribute('width');
   162→    expect(element).not.toHaveAttribute('height');
   163→
   164→    act(() => {
   165→      notifyResizeObserverChange([{ contentRect: { width: 100, height: 100 } }]);
   166→    });
   167→
   168→    expect(element.firstElementChild).toHaveAttribute('width', '100');
   169→    expect(element.firstElementChild).toHaveAttribute('height', '200');
   170→  });
   171→
   172→  it('should resize when debounced', () => {
   173→    vi.useFakeTimers();
   174→    const { container } = render(
   175→      <ResponsiveContainer id="testing-id-attr" width="100%" height={200} debounce={200}>
   176→        <div data-testid="inside" />
   177→      </ResponsiveContainer>,
   178→    );
   179→
   180→    const element = container.querySelector('.recharts-responsive-container');
   181→
   182→    act(() => {
   183→      notifyResizeObserverChange([{ contentRect: { width: 50, height: 50 } }]);
