        <div data-testid="inside" />
      </ResponsiveContainer>,
    );

    const responsiveContainerDiv = container.querySelector('.recharts-responsive-container');
    expect(responsiveContainerDiv).toHaveStyle({ width: '100%', height: '200px', 'min-width': '200px' });

    const elementsInside = screen.getAllByTestId('inside');

    expect(elementsInside).toHaveLength(4);
    expect(elementsInside[0]).toHaveStyle({
      width: '100%',
      height: '100%',
      'max-width': '400px',
      'max-height': '200px',
      'background-color': 'rgb(0, 0, 255)',
    });
    expect(elementsInside[0]).toHaveAttribute('height', '200');
    expect(elementsInside[0]).toHaveAttribute('width', '400');

    // all elements are cloned with the same style props besides their own style
    expect(elementsInside[1]).toHaveStyle({
      width: '100%',
      height: '100%',
      'max-width': '400px',
      'max-height': '200px',
      'background-color': 'rgba(0, 0, 0, 0)',
    });
    expect(elementsInside[1]).toHaveAttribute('height', '200');
    expect(elementsInside[1]).toHaveAttribute('width', '400');
  });

  it('should resize from large to small correctly', () => {
    const { container } = render(
      <ResponsiveContainer width="100%" height="100%">
        <div data-testid="inside" />
      </ResponsiveContainer>,
    );

    const element = container.querySelector('.recharts-responsive-container');

    // Simulate initial large size
    act(() => {
      notifyResizeObserverChange([{ contentRect: { width: 800, height: 600 } }]);
    });

    expect(element.firstElementChild).toHaveAttribute('width', '800');
    expect(element.firstElementChild).toHaveAttribute('height', '600');

    // Simulate resizing to smaller size (this is where the bug occurs)
    act(() => {
      notifyResizeObserverChange([{ contentRect: { width: 400, height: 300 } }]);
    });

    // The chart should shrink to the new smaller size
    expect(element.firstElementChild).toHaveAttribute('width', '400');
    expect(element.firstElementChild).toHaveAttribute('height', '300');
  });

  it('should resize from small to large correctly', () => {
    const { container } = render(
      <ResponsiveContainer width="100%" height="100%">
        <div data-testid="inside" />
      </ResponsiveContainer>,
    );

    const element = container.querySelector('.recharts-responsive-container');

    // Simulate initial small size
    act(() => {
      notifyResizeObserverChange([{ contentRect: { width: 400, height: 300 } }]);
    });

    expect(element.firstElementChild).toHaveAttribute('width', '400');
    expect(element.firstElementChild).toHaveAttribute('height', '300');

    // Simulate resizing to larger size (this should work)
    act(() => {
      notifyResizeObserverChange([{ contentRect: { width: 800, height: 600 } }]);
    });

    // The chart should grow to the new larger size
    expect(element.firstElementChild).toHaveAttribute('width', '800');
    expect(element.firstElementChild).toHaveAttribute('height', '600');
  });
});

